import{_ as o,C as d,o as t,c,a5 as a,b as i,w as r,a as n,E as l,a6 as h}from"./chunks/framework.BG2X7EgT.js";const v=JSON.parse('{"title":"GraphQL Gateway","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"reference/components/kubernetes-graphql-gateway.md","filePath":"reference/components/kubernetes-graphql-gateway.md"}'),p={name:"reference/components/kubernetes-graphql-gateway.md"};function u(m,e,g,b,y,k){const s=d("Mermaid");return t(),c("div",null,[e[1]||(e[1]=a('<h1 id="graphql-gateway" tabindex="-1">GraphQL Gateway <a class="header-anchor" href="#graphql-gateway" aria-label="Permalink to &quot;GraphQL Gateway&quot;">​</a></h1><p>The <strong>GraphQL Gateway</strong> exposes Kubernetes resources as a <a href="https://graphql.org/" target="_blank" rel="noreferrer">GraphQL</a> API. It enables UIs and tools to query, mutate, and subscribe to cluster resources in a developer-friendly way using the GraphQL ecosystem.</p><p>Within the Platform Mesh, the gateway serves as the <strong>primary interface layer</strong> between service consumers and the Kubernetes Resource Model (KRM). Instead of requiring direct interaction with Kubernetes API servers and <code>kubectl</code>, consumers can leverage GraphQL&#39;s typed, self-documenting query language to discover and manage resources across clusters.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>The gateway consists of two cooperating components:</p>',5)),(t(),i(h,null,{default:r(()=>[l(s,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20K%5B%22Kubernetes%20API%20Server(s)%22%5D%20--%3E%20L%5B%22Listener%22%5D%0A%20%20%20%20L%20--%20%22gRPC%20%2F%20file%22%20--%3E%20G%5B%22Gateway%22%5D%0A%20%20%20%20G%20--%3E%20API%5B%22GraphQL%20API%5Cn%2Fapi%2Fclusters%2F%7Bname%7D%2Fgraphql%22%5D%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a(`<ul><li><strong>Listener</strong> — Connects to one or more Kubernetes clusters, extracts their OpenAPI v3 specifications, and converts them into GraphQL schemas. It continuously watches for API changes and regenerates schemas as the cluster&#39;s API surface evolves.</li><li><strong>Gateway</strong> — Receives schemas from the listener, builds per-cluster GraphQL endpoints, and serves them over HTTP. It handles authentication, query validation, complexity analysis, and real-time subscriptions.</li></ul><h3 id="schema-transport" tabindex="-1">Schema transport <a class="header-anchor" href="#schema-transport" aria-label="Permalink to &quot;Schema transport&quot;">​</a></h3><p>The listener and gateway communicate via a configurable schema transport (<code>--schema-handler</code>), which both components must agree on:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td><code>grpc</code></td><td>The listener runs a gRPC server and the gateway connects as a client. Schemas are streamed in real-time. This is the <strong>recommended mode</strong>.</td></tr><tr><td><code>file</code></td><td>The listener writes schema JSON files to a shared directory. The gateway watches the directory for changes. Useful for debugging or when the two components cannot connect directly.</td></tr></tbody></table><h2 id="key-concepts" tabindex="-1">Key concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key concepts&quot;">​</a></h2><h3 id="dynamic-schema-generation" tabindex="-1">Dynamic schema generation <a class="header-anchor" href="#dynamic-schema-generation" aria-label="Permalink to &quot;Dynamic schema generation&quot;">​</a></h3><p>Unlike static GraphQL APIs, the gateway <strong>dynamically generates</strong> its entire schema from the Kubernetes OpenAPI v3 specification. Every resource type discovered on a cluster — including Custom Resource Definitions (CRDs) — automatically becomes available as typed GraphQL operations. When a new CRD is installed on a cluster, the gateway picks it up without any reconfiguration.</p><h3 id="per-cluster-endpoints" tabindex="-1">Per-cluster endpoints <a class="header-anchor" href="#per-cluster-endpoints" aria-label="Permalink to &quot;Per-cluster endpoints&quot;">​</a></h3><p>Each connected cluster gets its own GraphQL endpoint at <code>/api/clusters/{name}/graphql</code>. This allows consumers to target specific clusters while the gateway manages the connections centrally. A built-in GraphQL playground can be enabled for interactive exploration.</p><h3 id="clusteraccess-crd" tabindex="-1">ClusterAccess CRD <a class="header-anchor" href="#clusteraccess-crd" aria-label="Permalink to &quot;ClusterAccess CRD&quot;">​</a></h3><p>The <code>ClusterAccess</code> custom resource enables the gateway to connect to <strong>remote clusters</strong> beyond the local kubeconfig. It is part of the <code>gateway.platform-mesh.io</code> API group and defines connection details and authentication credentials for target clusters.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway.platform-mesh.io/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ClusterAccess</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-cluster</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  host</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://&lt;cluster-api-server&gt;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  auth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    serviceAccountRef</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">graphql-gateway</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">graphql-gateway</span></span></code></pre></div><p>The <code>ClusterAccess</code> CRD supports four mutually exclusive authentication methods:</p><table tabindex="0"><thead><tr><th>Method</th><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Service Account</td><td><code>auth.serviceAccountRef</code></td><td>Generates tokens from a service account on the management cluster</td></tr><tr><td>Bearer Token</td><td><code>auth.tokenSecretRef</code></td><td>References a secret containing a bearer token</td></tr><tr><td>Kubeconfig</td><td><code>auth.kubeconfigSecretRef</code></td><td>References a secret containing a full kubeconfig</td></tr><tr><td>Client Certificate</td><td><code>auth.clientCertificateRef</code></td><td>References a TLS secret for mTLS authentication</td></tr></tbody></table><p>A custom CA certificate can be provided via <code>ca.secretRef</code>.</p><h2 id="graphql-api" tabindex="-1">GraphQL API <a class="header-anchor" href="#graphql-api" aria-label="Permalink to &quot;GraphQL API&quot;">​</a></h2><p>For every Kubernetes resource discovered on a cluster, the gateway generates typed GraphQL operations covering queries, mutations, and subscriptions.</p><h3 id="queries" tabindex="-1">Queries <a class="header-anchor" href="#queries" aria-label="Permalink to &quot;Queries&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th><th>Key Arguments</th></tr></thead><tbody><tr><td><code>{pluralName}</code></td><td>List resources</td><td><code>namespace</code>, <code>labelselector</code>, <code>limit</code>, <code>continue</code>, <code>sortBy</code></td></tr><tr><td><code>{singularName}</code></td><td>Get a single resource</td><td><code>name</code>, <code>namespace</code></td></tr><tr><td><code>{singularName}Yaml</code></td><td>Get a single resource as YAML string</td><td><code>name</code>, <code>namespace</code></td></tr></tbody></table><h3 id="mutations" tabindex="-1">Mutations <a class="header-anchor" href="#mutations" aria-label="Permalink to &quot;Mutations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th><th>Key Arguments</th></tr></thead><tbody><tr><td><code>create{Name}</code></td><td>Create a resource</td><td><code>namespace</code>, <code>object</code>, <code>dryRun</code></td></tr><tr><td><code>update{Name}</code></td><td>Patch a resource (merge patch)</td><td><code>name</code>, <code>namespace</code>, <code>object</code>, <code>dryRun</code></td></tr><tr><td><code>delete{Name}</code></td><td>Delete a resource</td><td><code>name</code>, <code>namespace</code>, <code>dryRun</code></td></tr><tr><td><code>applyYaml</code></td><td>Create-or-update from a YAML string</td><td><code>yaml</code></td></tr></tbody></table><h3 id="subscriptions" tabindex="-1">Subscriptions <a class="header-anchor" href="#subscriptions" aria-label="Permalink to &quot;Subscriptions&quot;">​</a></h3><p>Real-time updates are delivered via Server-Sent Events (SSE):</p><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th><th>Key Arguments</th></tr></thead><tbody><tr><td><code>{group}_{version}_{singularName}</code></td><td>Watch a single resource</td><td><code>name</code>, <code>namespace</code>, <code>resourceVersion</code></td></tr><tr><td><code>{group}_{version}_{pluralName}</code></td><td>Watch a list of resources</td><td><code>namespace</code>, <code>labelselector</code>, <code>subscribeToAll</code>, <code>resourceVersion</code></td></tr></tbody></table><p>Each subscription event is an envelope with a <code>type</code> (<code>ADDED</code>, <code>MODIFIED</code>, <code>DELETED</code>) and the full <code>object</code>. By default, <code>MODIFIED</code> events are only sent when the fields selected in the subscription query actually change. Set <code>subscribeToAll: true</code> to receive all modification events.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The field-level change detection means clients can subscribe to exactly the data they need and only receive updates when that data actually changes — reducing noise and bandwidth.</p></div><h2 id="multi-cluster-support" tabindex="-1">Multi-cluster support <a class="header-anchor" href="#multi-cluster-support" aria-label="Permalink to &quot;Multi-cluster support&quot;">​</a></h2><p>The listener supports three provider modes, allowing the gateway to serve resources from different cluster topologies:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td><strong>single</strong> (default)</td><td>Watches the local cluster from the current kubeconfig</td></tr><tr><td><strong>kcp</strong></td><td>Connects to kcp workspaces via APIExport virtual workspaces</td></tr><tr><td><strong>multi</strong></td><td>Combines kcp and standard clusters, using separate kubeconfigs for each</td></tr></tbody></table><p>In any mode, the <code>ClusterAccess</code> CRD controller can be enabled to additionally manage remote clusters declaratively.</p><h3 id="integration-with-platform-mesh-control-planes" tabindex="-1">Integration with Platform Mesh control planes <a class="header-anchor" href="#integration-with-platform-mesh-control-planes" aria-label="Permalink to &quot;Integration with Platform Mesh control planes&quot;">​</a></h3><p>When running in <strong>kcp mode</strong>, the gateway integrates directly with the Platform Mesh <a href="/pr-preview/pr-174/concepts/control-planes.html">control plane</a> infrastructure. It discovers kcp workspaces and their APIs, making the resources offered by service providers through <code>APIExports</code> queryable via GraphQL. This enables service consumers to interact with provisioned capabilities through a unified, typed API surface rather than requiring direct <code>kubectl</code> access or workspace-aware tooling.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="gateway" tabindex="-1">Gateway <a class="header-anchor" href="#gateway" aria-label="Permalink to &quot;Gateway&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--schema-handler</code></td><td><code>file</code></td><td>How to receive schema updates: <code>file</code> or <code>grpc</code></td></tr><tr><td><code>--grpc-listener-address</code></td><td><code>localhost:50051</code></td><td>gRPC listener address</td></tr><tr><td><code>--gateway-port</code></td><td><code>8080</code></td><td>Port for the GraphQL server</td></tr><tr><td><code>--gateway-address</code></td><td><code>0.0.0.0</code></td><td>Bind address for the GraphQL server</td></tr><tr><td><code>--enable-playground</code></td><td><code>false</code></td><td>Enable the GraphQL playground UI</td></tr><tr><td><code>--cors-allowed-origins</code></td><td>—</td><td>Allowed origins for CORS</td></tr><tr><td><code>--endpoint-suffix</code></td><td><code>/graphql</code></td><td>Suffix appended to cluster endpoint paths</td></tr><tr><td><code>--request-timeout</code></td><td><code>60s</code></td><td>Max duration for GraphQL requests</td></tr><tr><td><code>--subscription-timeout</code></td><td><code>30m</code></td><td>Max duration for SSE subscriptions</td></tr><tr><td><code>--max-query-depth</code></td><td><code>10</code></td><td>Max query nesting depth</td></tr><tr><td><code>--max-query-complexity</code></td><td><code>1000</code></td><td>Max query complexity score</td></tr><tr><td><code>--max-query-batch-size</code></td><td><code>10</code></td><td>Max queries per batch request</td></tr><tr><td><code>--max-inflight-requests</code></td><td><code>400</code></td><td>Max concurrent requests</td></tr><tr><td><code>--max-inflight-subscriptions</code></td><td><code>50</code></td><td>Max concurrent SSE subscriptions</td></tr><tr><td><code>--token-review-cache-ttl</code></td><td><code>30s</code></td><td>Cache TTL for Kubernetes TokenReview results</td></tr></tbody></table><h3 id="listener" tabindex="-1">Listener <a class="header-anchor" href="#listener" aria-label="Permalink to &quot;Listener&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--kubeconfig</code></td><td>(auto-detected)</td><td>Path to kubeconfig</td></tr><tr><td><code>--multicluster-runtime-provider</code></td><td><code>single</code></td><td>Provider mode: <code>single</code>, <code>kcp</code>, or <code>multi</code></td></tr><tr><td><code>--schema-handler</code></td><td><code>file</code></td><td>Schema transport: <code>file</code> or <code>grpc</code></td></tr><tr><td><code>--grpc-listen-addr</code></td><td><code>:50051</code></td><td>gRPC server address</td></tr><tr><td><code>--reconciler-gvr</code></td><td><code>namespaces.v1</code></td><td>GroupVersionResource the reconciler watches</td></tr><tr><td><code>--anchor-resource</code></td><td><code>object.metadata.name == &#39;default&#39;</code></td><td>CEL expression to match the anchor resource</td></tr><tr><td><code>--enable-clusteraccess-controller</code></td><td><code>false</code></td><td>Enable the ClusterAccess CRD controller</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Set any limit flag to <code>0</code> to disable it.</p></div><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/kubernetes-graphql-gateway" target="_blank" rel="noreferrer">kubernetes-graphql-gateway</a></li><li><a href="https://github.com/platform-mesh/kubernetes-graphql-gateway/blob/main/config/crd/gateway.platform-mesh.io_clusteraccesses.yaml" target="_blank" rel="noreferrer">ClusterAccess CRD definition</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./portal.html">Portal</a></li><li><a href="./marketplace.html">Marketplace</a></li><li><a href="./virtual-workspaces.html">virtual-workspaces</a> — Platform Mesh virtual workspace apiserver fronted as GraphQL through <code>ClusterAccess</code></li><li><a href="/pr-preview/pr-174/concepts/architecture.html">Architecture</a></li></ul>`,42))])}const w=o(p,[["render",u]]);export{v as __pageData,w as default};
